B.Fm=new A.b9(null,"A partir de agora ser\xe3o apresentadas telas com as instru\xe7\xf5es das tarefas que voc\xea ir\xe1 responder.\r\n\nCertifique-se que esteja em um ambiente silencioso, sem est\xedmulos de distra\xe7\xe3o.\f\n\nEm algumas telas, sons ser\xe3o reproduzidos; portanto, \xe9 fundamental usar fones de ouvido ou ligar os alto-falantes do seu dispositivo.",!1,null,null,null)
B.Fn=new A.b9(null,"Seis (6) imagens foram apresentadas em algum momento do teste. Vamos encontr\xe1-los? Clique nas figuras que voc\xea lembrou. N\xe3o \xe9 obrigado(a) a encontrar todas as imagens. Fa\xe7a o seu melhor!\n",!1,null,null,null)
