B.Fv=new A.b9(null,"assets/olho7.png",!0,null,null,null)
B.Fw=new A.b9(null,"Nas pr\xf3ximas telas, ser\xe3o apresentadas algumas sequ\xeancias de n\xfameros, ap\xf3s visualiz\xe1-las voc\xea dever\xe1 marcar a resposta que corresponde \xe0 sequ\xeancia correta.",!1,null,null,null)
B.Fx=new A.b9(null,"Por favor, identifique express\xf5es e inten\xe7\xf5es das pessoas levando em considera\xe7\xe3o apenas a regi\xe3o dos olhos. Para cada imagem, selecione a palavra que melhor descreve os sentimentos, pensamentos ou impress\xf5es que a pessoa em quest\xe3o est\xe1 transmitindo.",!1,null,null,null)
